INSERT INTO questions (question_text, choices, correct_answer, explanation, subject, topic, difficulty, exam_type) VALUES
('In a right triangle, the sine of an angle is defined as:', '["Opposite ÷ Hypotenuse", "Adjacent ÷ Hypotenuse", "Opposite ÷ Adjacent", "Hypotenuse ÷ Opposite"]', 'A', 'SOH-CAH-TOA: Sin = Opposite/Hypotenuse, Cos = Adjacent/Hypotenuse, Tan = Opposite/Adjacent.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('What is cos(60°)?', '["1/2", "√3/2", "√2/2", "1"]', 'A', 'cos(60°) = 1/2. This is one of the standard angle values: cos(0°)=1, cos(30°)=√3/2, cos(45°)=√2/2, cos(60°)=1/2, cos(90°)=0.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('What is sin(30°)?', '["1/2", "√3/2", "1", "√2/2"]', 'A', 'sin(30°) = 1/2. Standard values: sin(0°)=0, sin(30°)=1/2, sin(45°)=√2/2, sin(60°)=√3/2, sin(90°)=1.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('What is tan(45°)?', '["1", "0", "√3", "1/√3"]', 'A', 'tan(45°) = sin(45°)/cos(45°) = (√2/2)/(√2/2) = 1.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('What is the tangent of an angle defined as?', '["Opposite ÷ Adjacent", "Adjacent ÷ Hypotenuse", "Opposite ÷ Hypotenuse", "Hypotenuse ÷ Adjacent"]', 'A', 'Using SOH-CAH-TOA: Tangent = Opposite/Adjacent. Also, tan θ = sin θ / cos θ.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('In a right triangle with hypotenuse 10 and one angle of 30°, what is the length of the side opposite that angle?', '["5", "8.66", "10", "5.77"]', 'A', 'sin(30°) = opposite/hypotenuse = opposite/10. So opposite = 10 × sin(30°) = 10 × 0.5 = 5.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('What is the sum sin²θ + cos²θ equal to?', '["1", "0", "tan²θ", "2"]', 'A', 'The Pythagorean identity: sin²θ + cos²θ = 1, for any angle θ. This is derived from the Pythagorean theorem applied to the unit circle.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('A train travels 120 km in 2 hours. What is its average speed?', '["60 km/h", "240 km/h", "60 km", "120 km/h"]', 'A', 'Speed = Distance / Time = 120 km / 2 h = 60 km/h.', 'Mathematics', 'Word Problems', 'easy', 'secondary'),
('A box contains 8 red balls and 12 blue balls. What fraction of the balls are red?', '["2/5", "3/5", "2/3", "1/4"]', 'A', 'Total balls = 8 + 12 = 20. Fraction red = 8/20 = 2/5.', 'Mathematics', 'Word Problems', 'easy', 'secondary'),
('What is sin(90°)?', '["1", "0", "√2/2", "√3/2"]', 'A', 'sin(90°) = 1. At 90°, the opposite side equals the hypotenuse in the unit circle, giving a sine value of 1.', 'Mathematics', 'Trigonometry', 'easy', 'secondary'),
('A class has 35 students. 60% are girls. How many boys are there?', '["14", "21", "15", "20"]', 'A', 'Girls = 60% × 35 = 21. Boys = 35 - 21 = 14.', 'Mathematics', 'Word Problems', 'easy', 'secondary'),
('If a car depreciates in value by 15% per year, and is originally worth ₱500,000, what is it worth after 1 year?', '["₱425,000", "₱475,000", "₱515,000", "₱450,000"]', 'A', 'Depreciation = 15% × 500,000 = 75,000. New value = 500,000 - 75,000 = ₱425,000.', 'Mathematics', 'Word Problems', 'medium', 'secondary'),
('What is cos(0°)?', '["1", "0", "√2/2", "-1"]', 'A', 'cos(0°) = 1. At 0°, the adjacent side equals the hypotenuse in the unit circle, giving a cosine value of 1.', 'Mathematics', 'Trigonometry', 'easy', 'secondary'),
('A pipe can fill a tank in 4 hours. Another pipe can fill it in 6 hours. If both pipes work together, how long will it take to fill the tank?', '["2.4 hours", "5 hours", "3 hours", "10 hours"]', 'A', 'Combined rate = 1/4 + 1/6 = 3/12 + 2/12 = 5/12 per hour. Time = 12/5 = 2.4 hours.', 'Mathematics', 'Word Problems', 'hard', 'secondary'),
('What angle has a sine value of √3/2?', '["60°", "30°", "45°", "90°"]', 'A', 'sin(60°) = √3/2. Also sin(120°) = √3/2, but among standard angles 0°-90°, the answer is 60°.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('A merchant buys goods for ₱800 and sells them for ₱1,000. What is the profit percentage?', '["25%", "20%", "30%", "15%"]', 'A', 'Profit = ₱1,000 - ₱800 = ₱200. Profit % = (200/800) × 100% = 25%.', 'Mathematics', 'Word Problems', 'medium', 'secondary'),
('If sin θ = 3/5, what is cos θ? (assuming θ is in the first quadrant)', '["4/5", "5/3", "3/4", "5/4"]', 'A', 'Using sin²θ + cos²θ = 1: (3/5)² + cos²θ = 1 → 9/25 + cos²θ = 1 → cos²θ = 16/25 → cos θ = 4/5.', 'Mathematics', 'Trigonometry', 'hard', 'secondary'),
('Maria is 3 times as old as her sister. In 5 years, she will be twice as old. How old is Maria now?', '["15", "10", "12", "18"]', 'A', 'Let sister''s age = x, Maria''s = 3x. In 5 years: 3x + 5 = 2(x + 5) → 3x + 5 = 2x + 10 → x = 5. Maria = 3×5 = 15.', 'Mathematics', 'Word Problems', 'hard', 'secondary'),
('What is the reciprocal of sin θ?', '["Cosecant (csc θ)", "Cotangent (cot θ)", "Secant (sec θ)", "Cosine (cos θ)"]', 'A', 'The reciprocal trigonometric functions: csc θ = 1/sin θ, sec θ = 1/cos θ, cot θ = 1/tan θ.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('A swimming pool is 25 m long and 10 m wide. If it is filled to a depth of 2 m, how many cubic meters of water does it hold?', '["500 m³", "250 m³", "50 m³", "700 m³"]', 'A', 'Volume = length × width × depth = 25 × 10 × 2 = 500 m³.', 'Mathematics', 'Word Problems', 'easy', 'secondary'),
('What is the reference angle for 150°?', '["30°", "60°", "150°", "45°"]', 'A', 'The reference angle is the acute angle between the terminal side and the x-axis. For 150° (in Q2): reference angle = 180° - 150° = 30°.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('A man walks 3 km east and then 4 km north. How far is he from his starting point?', '["5 km", "7 km", "6 km", "3.5 km"]', 'A', 'This forms a right triangle. Distance = √(3² + 4²) = √(9 + 16) = √25 = 5 km.', 'Mathematics', 'Word Problems', 'medium', 'secondary'),
('What is the value of sin(180°)?', '["0", "1", "-1", "√2/2"]', 'A', 'sin(180°) = 0. At 180°, the point on the unit circle is at (-1, 0), and the y-coordinate (sine) is 0.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('If a number is increased by 20%, then decreased by 20%, what happens to the original value?', '["It decreases by 4%", "It stays the same", "It increases by 4%", "It decreases by 2%"]', 'A', 'Let original = 100. After 20% increase: 120. After 20% decrease: 120 × 0.8 = 96. Net change = -4%.', 'Mathematics', 'Word Problems', 'hard', 'secondary'),
('In which quadrant is the angle 225°?', '["Third quadrant (Q3)", "First quadrant (Q1)", "Second quadrant (Q2)", "Fourth quadrant (Q4)"]', 'A', '225° is between 180° and 270°, placing it in the Third Quadrant (Q3), where both sin and cos are negative.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('Two numbers have a sum of 50 and a difference of 14. What are the two numbers?', '["32 and 18", "30 and 20", "36 and 14", "28 and 22"]', 'A', 'Let x + y = 50 and x - y = 14. Adding: 2x = 64, x = 32. Then y = 50 - 32 = 18.', 'Mathematics', 'Word Problems', 'medium', 'secondary'),
('What is cos(90°)?', '["0", "1", "-1", "√2/2"]', 'A', 'cos(90°) = 0. At 90°, the point on the unit circle is at (0, 1), and the x-coordinate (cosine) is 0.', 'Mathematics', 'Trigonometry', 'easy', 'secondary'),
('A store is selling items at 30% off. If the original price is ₱1,500, what is the sale price?', '["₱1,050", "₱1,200", "₱450", "₱1,100"]', 'A', 'Discount = 30% × 1,500 = 450. Sale price = 1,500 - 450 = ₱1,050.', 'Mathematics', 'Word Problems', 'easy', 'secondary'),
('What is the period of the sine function y = sin(x)?', '["360° or 2π radians", "180° or π radians", "90° or π/2 radians", "720° or 4π radians"]', 'A', 'The sine function completes one full cycle every 360° (2π radians). This is its period.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('If 6 workers can complete a project in 10 days, how many days will 10 workers take (same pace)?', '["6 days", "4 days", "8 days", "5 days"]', 'A', 'Total work = 6 × 10 = 60 worker-days. With 10 workers: 60 / 10 = 6 days.', 'Mathematics', 'Word Problems', 'medium', 'secondary'),
('What is the exact value of tan(30°)?', '["1/√3 or √3/3", "√3", "1", "√2/2"]', 'A', 'tan(30°) = sin(30°)/cos(30°) = (1/2)/(√3/2) = 1/√3 = √3/3 (rationalized).', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('Ana can type 60 words per minute. How long will it take her to type a 1,800-word document?', '["30 minutes", "60 minutes", "3 hours", "90 minutes"]', 'A', 'Time = 1,800 words ÷ 60 words/min = 30 minutes.', 'Mathematics', 'Word Problems', 'easy', 'secondary'),
('What is the value of sin(270°)?', '["-1", "0", "1", "√2/2"]', 'A', 'sin(270°) = -1. At 270°, the point on the unit circle is at (0, -1), and the y-coordinate (sine) is -1.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('A triangle has sides 5, 12, and 13. What type of triangle is it?', '["Right triangle", "Equilateral triangle", "Obtuse triangle", "Isosceles triangle"]', 'A', 'Check: 5² + 12² = 25 + 144 = 169 = 13². Since a² + b² = c², it is a right triangle (Pythagorean triple 5-12-13).', 'Mathematics', 'Word Problems', 'medium', 'secondary'),
('What is the amplitude of y = 3sin(x)?', '["3", "1", "π", "6"]', 'A', 'The amplitude of y = A sin(x) is |A|. For y = 3sin(x), the amplitude is 3, meaning the function oscillates between -3 and 3.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('If simple interest on ₱10,000 for 2 years is ₱2,000, what is the annual interest rate?', '["10%", "20%", "5%", "15%"]', 'A', 'Simple interest formula: I = PRT. 2,000 = 10,000 × R × 2 → R = 2,000/20,000 = 0.10 = 10%.', 'Mathematics', 'Word Problems', 'medium', 'secondary'),
('What does the inverse sine function (sin⁻¹ or arcsin) find?', '["The angle whose sine equals the given value", "The sine of a given angle", "The reciprocal of sine", "The cosine of a given angle"]', 'A', 'The inverse sine (arcsin) function finds the angle whose sine equals the given value. If sin θ = 0.5, then arcsin(0.5) = 30°.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('A car travels at 80 km/h. How long will it take to cover 200 km?', '["2.5 hours", "2 hours", "3 hours", "160 hours"]', 'A', 'Time = Distance / Speed = 200 / 80 = 2.5 hours.', 'Mathematics', 'Word Problems', 'easy', 'secondary'),
('In which quadrant is sin positive and cos negative?', '["Second quadrant (Q2)", "First quadrant (Q1)", "Third quadrant (Q3)", "Fourth quadrant (Q4)"]', 'A', 'In Q2 (90° to 180°): sin is positive (y > 0) and cos is negative (x < 0). Memory aid: "All Students Take Calculus" — All positive in Q1, Sin positive in Q2, Tan positive in Q3, Cos positive in Q4.', 'Mathematics', 'Trigonometry', 'hard', 'secondary'),
('A mixture is 40% alcohol. How much alcohol is in 500 mL of the mixture?', '["200 mL", "150 mL", "300 mL", "40 mL"]', 'A', 'Alcohol = 40% × 500 = 0.40 × 500 = 200 mL.', 'Mathematics', 'Word Problems', 'easy', 'secondary'),
('What is the value of cos(180°)?', '["-1", "0", "1", "√3/2"]', 'A', 'cos(180°) = -1. At 180°, the point on the unit circle is at (-1, 0), and the x-coordinate (cosine) is -1.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('A father is 4 times as old as his son. In 12 years, he will be twice as old as his son. How old is the son now?', '["6", "8", "12", "4"]', 'A', 'Let son = x, father = 4x. In 12 years: 4x + 12 = 2(x + 12) → 4x + 12 = 2x + 24 → 2x = 12 → x = 6.', 'Mathematics', 'Word Problems', 'hard', 'secondary'),
('What is the range of the function y = sin(x)?', '["-1 ≤ y ≤ 1", "0 ≤ y ≤ 1", "-∞ < y < ∞", "0 ≤ y ≤ 2π"]', 'A', 'The range of y = sin(x) is [-1, 1] — the sine function oscillates between -1 and 1 for all real x values.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('The perimeter of a rectangle is 40 cm. If the length is 12 cm, what is the width?', '["8 cm", "10 cm", "16 cm", "28 cm"]', 'A', 'Perimeter = 2(l + w). 40 = 2(12 + w) → 20 = 12 + w → w = 8 cm.', 'Mathematics', 'Word Problems', 'easy', 'secondary'),
('Using the Law of Sines, sin A / a = sin B / b. If A = 30°, a = 5, and b = 8, what is sin B?', '["0.8", "0.6", "1.6", "0.4"]', 'A', 'sin B / b = sin A / a → sin B / 8 = sin 30° / 5 = 0.5 / 5 = 0.1 → sin B = 0.1 × 8 = 0.8.', 'Mathematics', 'Trigonometry', 'hard', 'secondary'),
('A bus and a car start from the same point. The bus travels at 40 km/h and the car at 60 km/h in the same direction. After 3 hours, how far apart are they?', '["60 km", "180 km", "120 km", "30 km"]', 'A', 'Distance bus = 40 × 3 = 120 km. Distance car = 60 × 3 = 180 km. Difference = 180 - 120 = 60 km.', 'Mathematics', 'Word Problems', 'medium', 'secondary'),
('What does 1 radian equal in degrees?', '["180°/π ≈ 57.3°", "π ≈ 3.14°", "90°", "360°/π ≈ 114.6°"]', 'A', '1 radian = 180°/π ≈ 57.3°. To convert from radians to degrees, multiply by 180/π.', 'Mathematics', 'Trigonometry', 'hard', 'secondary'),
('If the area of a square is 64 cm², what is the length of each side?', '["8 cm", "16 cm", "4 cm", "32 cm"]', 'A', 'Area = side². 64 = side² → side = √64 = 8 cm.', 'Mathematics', 'Word Problems', 'easy', 'secondary'),
('What is sin(45°)?', '["√2/2", "1/2", "√3/2", "1"]', 'A', 'sin(45°) = √2/2 ≈ 0.707. In a 45-45-90 triangle, the legs are equal and the hypotenuse = leg × √2.', 'Mathematics', 'Trigonometry', 'medium', 'secondary'),
('Three consecutive odd integers have a sum of 57. What are they?', '["17, 19, 21", "18, 19, 20", "15, 19, 23", "19, 21, 23"]', 'A', 'Let the integers be x, x+2, x+4. Sum: 3x + 6 = 57 → 3x = 51 → x = 17. So: 17, 19, 21.', 'Mathematics', 'Word Problems', 'medium', 'secondary'),
('What is the co-function relationship? sin(θ) = cos(___)?', '["90° - θ", "θ + 90°", "180° - θ", "θ - 90°"]', 'A', 'Co-function identities: sin(θ) = cos(90° - θ). "Co" in cosine means "complement" — cosine of an angle equals sine of its complement.', 'Mathematics', 'Trigonometry', 'hard', 'secondary');
